  ('aboriginal-8b44517b-moex-00092', 'aboriginal-8b44517b', 'aboriginal-8b44517b-moex-110-d1a761c9', 'sub-aboriginal-8b44517b-04', NULL, 'single_choice', '下列何者屬於行政執行之間接強制方法？ 罰鍰  代履行  註銷證照  斷水斷電', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "505", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 34, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "勞工行政"}'::jsonb, NULL),
