  ('aboriginal-8b44517b-moex-00095', 'aboriginal-8b44517b', 'aboriginal-8b44517b-moex-110-d1a761c9', 'sub-aboriginal-8b44517b-04', NULL, 'single_choice', '下列何者非屬行政處分？', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "505", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 37, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('aboriginal-8b44517b-moex-00096', 'aboriginal-8b44517b', 'aboriginal-8b44517b-moex-110-d1a761c9', 'sub-aboriginal-8b44517b-04', NULL, 'single_choice', '有關行政計畫之敘述，下列何者錯誤？ 行政機關雖享有所謂計畫高權，行政法院非不得審查行政機關所訂定之行政計畫 在大規模之計畫有所謂先行裁決，此種多階段之決定有行政自我拘束原則之適用 如經確定計畫裁決程序，因具核准及形成與集中事權效果，當事人不得再行爭訟 行政機關變更計畫時，人民如有權利受損之情形，仍得依國家賠償法尋求救濟', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "505", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 38, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('aboriginal-8b44517b-moex-00097', 'aboriginal-8b44517b', 'aboriginal-8b44517b-moex-110-d1a761c9', 'sub-aboriginal-8b44517b-04', NULL, 'single_choice', '有關訴願之敘述，下列何者正確？ 原處分機關認為訴願有理由者，應自行撤銷原處分，毋須通知訴願管轄機關 原處分機關認為訴願有理由者，自行撤銷原處分後，訴願管轄機關應為訴願駁回之決定 訴願人誤向訴願管轄機關以外之機關提起訴願者，該機關應為訴願不受理之決定 受理訴願機關認為有必要時，得依職權通知訴願人及原處分機關進行言詞辯論', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "505", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 39, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('aboriginal-8b44517b-moex-00098', 'aboriginal-8b44517b', 'aboriginal-8b44517b-moex-110-d1a761c9', 'sub-aboriginal-8b44517b-04', NULL, 'single_choice', '依訴願法第77條規定，下列何者非屬不受理決定之事由？ 提起訴願逾法定期間    行政處分已不存在 對已撤回之訴願事件重行提起訴願  為決定基礎之證物，係偽造或變造', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "505", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 40, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('aboriginal-8b44517b-moex-00099', 'aboriginal-8b44517b', 'aboriginal-8b44517b-moex-110-d1a761c9', 'sub-aboriginal-8b44517b-04', NULL, 'single_choice', '依訴願法規定，關於訴願審議程序之敘述，下列何者錯誤？ 場陳述意見 日未完備者，得再為辯論', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "505", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 41, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('aboriginal-8b44517b-moex-00100', 'aboriginal-8b44517b', 'aboriginal-8b44517b-moex-110-d1a761c9', 'sub-aboriginal-8b44517b-04', NULL, 'single_choice', '甲、乙公同共有之土地被徵收，甲針對徵收處分提起撤銷之訴，有關訴訟中乙參加訴訟之敘述，下列 何者錯誤？ 訴訟標的對於甲及乙必須合一確定 行政法院應以裁定命乙參加訴訟 乙之行為有利益於共同訴訟人者，其效力及於全體 乙對於命其參加之裁定得聲明不服', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "505", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 42, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('aboriginal-8b44517b-moex-00101', 'aboriginal-8b44517b', 'aboriginal-8b44517b-moex-110-d1a761c9', 'sub-aboriginal-8b44517b-04', NULL, 'single_choice', '行政法院審查古蹟或歷史建築等文化資產審議決定時，關於判斷餘地之審查，下列敘述何者錯誤？ 法院得審查文化資產審議決定所憑藉的基礎事實是否正確 法院得審查審議程序是否符合正當行政程序及審議委員會之組織是否合法 法院得審查文化資產保存價值判斷之結論與相關學術領域多數見解是否相符 文資審議決定對當事人基本權之限制越重大，應採越高之審查密度', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "505", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 43, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "勞工行政"}'::jsonb, NULL)
